```javascript
const searchInput = document.getElementById('search-input');
const suggestionsDiv = document.getElementById('suggestions');
const resultsDiv = document.getElementById('results');

// Rechercher les suggestions basées sur l'entrée
searchInput.addEventListener('input', async () => {
  const query = searchInput.value.trim();
  if (query.length >= 3) {
    const response = await fetch(`/api/keywords?search=${query}`);
    const data = await response.json();
    if (data.status === 200) {
      suggestionsDiv.innerHTML = data.data
        .map((keyword) => `<div class="tag-suggestion">${keyword.keyword}</div>`)
        .join('');
    } else {
      suggestionsDiv.innerHTML = '';
      console.error('Erreur lors de la récupération des suggestions :', data.message);
    }
  } else {
    suggestionsDiv.innerHTML = '';
  }
});

// Gérer le clic sur une suggestion pour effectuer une recherche
suggestionsDiv.addEventListener('click', (e) => {
  if (e.target && e.target.classList.contains('tag-suggestion')) {
    const tag = e.target.textContent;
    searchData([tag]);
  }
});

// Rechercher les données basées sur les tags
const searchData = async (tags) => {
  if (tags.length === 0) {
    resultsDiv.innerHTML = '<p>Aucun résultat trouvé.</p>';
    return;
  }

  const response = await fetch(`/api/search-data?tags=${tags.join(',')}`);
  const data = await response.json();
  if (data.status === 200) {
    if (data.data.length === 0) {
      resultsDiv.innerHTML = '<p>Aucun résultat trouvé.</p>';
    } else {
      resultsDiv.innerHTML = data.data
        .map(
          (item) =>
            `<div class="result-item">
              <h3>${item.name}</h3>
              <p><strong>Data :</strong> ${item.data || 'Aucun contenu'}</p>
              <p><strong>Tags :</strong> ${item.tags}</p>
            </div>`
        )
        .join('');
    }
  } else {
    resultsDiv.innerHTML = `<p>Erreur : ${data.message}</p>`;
    console.error('Erreur lors de la recherche des données :', data.message);
  }
};
```

