### Étape 4 : Mise à jour du backend pour la recherche de données

La route `/api/search-data` est déjà configurée pour rechercher des données basées sur les tags. Voici un rappel de la structure :

```javascript
router.get('/search-data', async (req, res) => {
  try {
    const tags = req.query.tags ? req.query.tags.split(',') : [];
    if (tags.length === 0) {
      return res.json({ status: 400, data: null, message: 'Veuillez spécifier au moins un tag.' });
    }

    const placeholders = tags.map(() => '?').join(',');
    db.all(
      `
      SELECT d.id, d.name, d.data, GROUP_CONCAT(k.keyword) AS tags
      FROM datas d
      LEFT JOIN dataKeyword dk ON d.id = dk.dataId
      LEFT JOIN keywords k ON dk.keywordId = k.id
      WHERE k.keyword IN (${placeholders})
      GROUP BY d.id
      ORDER BY d.dateAdd DESC
      `,
      tags,
      (err, rows) => {
        if (err) {
          return res.json({ status: 500, data: null, message: 'Erreur lors de la recherche.' });
        }
        res.json({ status: 200, data: rows });
      }
    );
  } catch (err) {
    res.json({ status: 500, data: null, message: 'Erreur inattendue.' });
  }
});
```

