### Code complet de `dataRoutes.js`

```javascript
const express = require('express');
const multer = require('multer');
const path = require('path');
const { formatResponse } = require('../../utils/helpers');
const db = require('../../config/database');

const router = express.Router();

// Configuration Multer pour l'upload
const upload = multer({
  dest: 'uploads/',
  limits: { fileSize: 5 * 1024 * 1024 }, // Limite de 5 Mo
});

// Route pour récupérer les mots-clés correspondant à une recherche
router.get('/keywords', async (req, res) => {
  try {
    const query = req.query.search || '';
    db.all(
      `SELECT * FROM keywords WHERE keyword LIKE ?`,
      [`%${query}%`],
      (err, rows) => {
        if (err) {
          return res.json(formatResponse(500, null, 'Erreur lors de la récupération des mots-clés.'));
        }
        res.json(formatResponse(200, rows));
      }
    );
  } catch (err) {
    res.json(formatResponse(500, null, 'Erreur inattendue.'));
  }
});

// Route pour récupérer les tags les plus populaires
router.get('/top-tags', async (req, res) => {
  try {
    const defaultLimit = 5;

    db.get(`SELECT value FROM settings WHERE key = 'max_displayed_suggested_tags'`, (err, row) => {
      if (err) {
        return res.json({ status: 500, data: null, message: 'Erreur lors de la récupération du paramètre.' });
      }

      const limit = row ? parseInt(row.value, 10) : defaultLimit;

      db.all(
        `
        SELECT k.keyword, COUNT(dk.dataId) AS usage_count
        FROM keywords k
        LEFT JOIN dataKeyword dk ON k.id = dk.keywordId
        GROUP BY k.id
        ORDER BY usage_count DESC
        LIMIT ?
        `,
        [limit],
        (err, rows) => {
          if (err) {
            return res.json({ status: 500, data: null, message: 'Erreur lors de la récupération des tags.' });
          }
          res.json({ status: 200, data: rows });
        }
      );
    });
  } catch (err) {
    res.json({ status: 500, data: null, message: 'Erreur inattendue.' });
  }
});

// Route pour rechercher des données basées sur des tags
router.get('/search-data', async (req, res) => {
  try {
    const tags = req.query.tags ? req.query.tags.split(',') : [];
    if (tags.length === 0) {
      return res.json(formatResponse(400, null, 'Veuillez spécifier au moins un tag.'));
    }

    const placeholders = tags.map(() => '?').join(',');
    db.all(
      `
      SELECT d.id, d.name, d.data, GROUP_CONCAT(k.keyword) AS tags
      FROM datas d
      LEFT JOIN dataKeyword dk ON d.id = dk.dataId
      LEFT JOIN keywords k ON dk.keywordId = k.id
      WHERE k.keyword IN (${placeholders})
      GROUP BY d.id
      ORDER BY d.dateAdd DESC
      `,
      tags,
      (err, rows) => {
        if (err) {
          res.json(formatResponse(500, null, 'Erreur lors de la recherche.'));
        } else {
          res.json(formatResponse(200, rows));
        }
      }
    );
  } catch (err) {
    res.json(formatResponse(500, null, 'Erreur inattendue.'));
  }
});

// Route pour ajouter une donnée
router.post('/data', upload.single('file'), async (req, res) => {
  try {
    const { name, data, tags } = req.body;
    const file = req.file;

    if (!name || (!data && !file)) {
      return res.json(formatResponse(400, null, 'Le nom et un contenu ou un fichier sont obligatoires.'));
    }

    const tagList = tags ? tags.split(',') : [];
    const filePath = file ? file.path : null;

    db.run(
      `INSERT INTO datas (name, data) VALUES (?, ?)`,
      [name, data || filePath],
      function (err) {
        if (err) {
          return res.json(formatResponse(500, null, 'Erreur lors de l\'ajout des données.'));
        }

        const dataId = this.lastID;
        const tagPromises = tagList.map((tag) => {
          return new Promise((resolve, reject) => {
            db.run(`INSERT OR IGNORE INTO keywords (keyword) VALUES (?)`, [tag], function (err) {
              if (err) return reject(err);

              const keywordId = this.lastID || null;
              db.run(`INSERT INTO dataKeyword (dataId, keywordId) VALUES (?, ?)`, [dataId, keywordId], (err) => {
                if (err) return reject(err);
                resolve();
              });
            });
          });
        });

        Promise.all(tagPromises)
          .then(() => res.json(formatResponse(201, { id: dataId }, 'Donnée ajoutée avec succès.')))
          .catch(() => res.json(formatResponse(500, null, 'Erreur lors de l\'association des tags.')));
      }
    );
  } catch (err) {
    res.json(formatResponse(500, null, 'Erreur inattendue.'));
  }
});

module.exports = router;
```

