export const setupAutoComplete = (inputElement, suggestionsContainer, dataEndpoint, onTagToggle) => {
  const loadSuggestions = async (query) => {
    try {
      const response = await fetch(`${dataEndpoint}?search=${query}`);
      const data = await response.json();
      if (data.status === 200) {
        suggestionsContainer.innerHTML = data.data
          .map((tag) => `<span class="tag unselected">${tag.keyword}</span>`)
          .join('');
      } else {
        suggestionsContainer.innerHTML = '<p>Aucune suggestion trouvée.</p>';
      }
    } catch (err) {
      console.error('Erreur lors du chargement des suggestions:', err);
    }
  };

  inputElement.addEventListener('input', () => {
    const query = inputElement.value.trim();
    if (query.length >= 3) {
      loadSuggestions(query);
    } else {
      suggestionsContainer.innerHTML = '';
    }
  });

  suggestionsContainer.addEventListener('click', (e) => {
    if (e.target && e.target.classList.contains('tag')) {
      onTagToggle(e.target);
    }
  });
};
```

