### **3. `app.js`**

```javascript
import { setupAutoComplete } from './services/autoComplete.js';

document.addEventListener('DOMContentLoaded', () => {
  const searchInput = document.getElementById('search-input');
  const suggestionsDiv = document.getElementById('suggestions');
  const topTagsDiv = document.getElementById('top-tags');
  const searchTagsDiv = document.getElementById('search-tags');
  const resultsDiv = document.getElementById('results');
  const selectedTags = [];
  const modalInput = document.getElementById('modal-input');
  const modalSuggestionsDiv = document.getElementById('modal-suggestions');

  const toggleTag = (tagElement) => {
    if (tagElement.classList.contains('selected')) {
      tagElement.classList.remove('selected');
      tagElement.classList.add('unselected');
    } else {
      tagElement.classList.remove('unselected');
      tagElement.classList.add('selected');
    }
  };

  const updateResults = async () => {
    if (selectedTags.length === 0) {
      resultsDiv.innerHTML = '<p>Aucun tag sélectionné.</p>';
      return;
    }

    const response = await fetch(`/api/search-data?tags=${selectedTags.join(',')}`);
    const data = await response.json();
    if (data.status === 200) {
      resultsDiv.innerHTML = data.data
        .map(
          (item) => `
            <div class="result-item">
              <h3>${item.name}</h3>
              <p><strong>Data:</strong> ${item.data || 'Aucun contenu'}</p>
              <p><strong>Tags:</strong> ${item.tags}</p>
            </div>`
        )
        .join('');
    } else {
      resultsDiv.innerHTML = `<p>Erreur : ${data.message}</p>`;
      console.error('Erreur lors de la recherche des données:', data.message);
    }
  };

  const loadTopTags = async () => {
    try {
      const response = await fetch('/api/top-tags');
      const data = await response.json();
      if (data.status === 200) {
        topTagsDiv.innerHTML = data.data
          .map((tag) => `<span class="tag unselected">${tag.keyword}</span>`)
          .join('');
      } else {
        console.error('Erreur lors du chargement des tags populaires :', data.message);
      }
    } catch (err) {
      console.error('Erreur lors de la connexion au serveur :', err);
    }
  };

  const addTagToSelection = (tag) => {
    if (!selectedTags.includes(tag)) {
      selectedTags.push(tag);
      updateResults();
    }
  };

  // Activer la saisie semi-automatique
  setupAutoComplete(searchInput, suggestionsDiv, '/api/keywords', (tagElement) => {
    const tag = tagElement.textContent.trim();
    addTagToSelection(tag);
    tagElement.classList.add('selected');
  });

  setupAutoComplete(modalInput, modalSuggestionsDiv, '/api/keywords', (tagElement) => {
    const tag = tagElement.textContent.trim();
    toggleTag(tagElement);
  });

  loadTopTags();
});
```

