          .join('');
      } else {
        console.error('Erreur lors du chargement des tags dans la modal :', data.message);
      }
    } catch (err) {
      console.error('Erreur lors de la connexion au serveur pour les suggestions de la modal :', err);
    }
  };

  // Ajouter un tag à la sélection dans la modal
  const toggleModalTag = (tagElement) => {
    const tag = tagElement.textContent.trim();
    if (tagElement.classList.contains('selected')) {
      tagElement.classList.remove('selected');
      modalSelectedTags.splice(modalSelectedTags.indexOf(tag), 1);
    } else {
      tagElement.classList.add('selected');
      modalSelectedTags.push(tag);
    }
  };

  // Valider et envoyer les données depuis la modal
  validateDataButton.addEventListener('click', async () => {
    const dataName = document.getElementById('data-name').value.trim();
    const dataFile = document.getElementById('data-file').files[0];
    const dataContent = document.getElementById('data-content').value.trim();

    if (!dataName || (!dataContent && !dataFile)) {
      alert('Veuillez remplir le nom et ajouter un contenu ou un fichier.');
      return;
    }

    const formData = new FormData();
    formData.append('name', dataName);
    if (dataContent) formData.append('data', dataContent);
    if (dataFile) formData.append('file', dataFile);
    formData.append('tags', modalSelectedTags.join(','));

    try {
      const response = await fetch('/api/data', { method: 'POST', body: formData });
      const data = await response.json();
      if (data.status === 201) {
        alert('Donnée ajoutée avec succès.');
        closeAddDataModal();
      } else {
        alert(`Erreur : ${data.message}`);
      }
    } catch (err) {
      console.error('Erreur lors de l\'ajout de la donnée :', err);
      alert('Erreur lors de l\'ajout de la donnée.');
    }
  });

  // Gérer l'ouverture et la fermeture de la modal
  if (openModalButton) {
    openModalButton.addEventListener('click', openAddDataModal);
  } else {
    console.error("Erreur : Bouton 'Ajouter une donnée' introuvable.");
  }

  if (cancelDataButton) {
    cancelDataButton.addEventListener('click', closeAddDataModal);
  } else {
    console.error("Erreur : Bouton 'Annuler' dans la modal introuvable.");
  }

  // Ajouter un tag sélectionné à #search-tags
  const addTagToSearchTags = (tag) => {
    if (!selectedTags.includes(tag)) {
      selectedTags.push(tag);
      updateSearchTagsDisplay();
      updateTopTags();
      updateResults();
    }
  };

  // Mettre à jour l'affichage des tags dans #search-tags
  const updateSearchTagsDisplay = () => {
    searchTagsDiv.innerHTML = selectedTags
      .map((tag) => `<span class="tag selected">${tag}</span>`)
      .join('');
  };

  // Mettre à jour #top-tags en fonction des tags sélectionnés
  const updateTopTags = async () => {
    try {
      const response = await fetch(`/api/top-tags?tags=${selectedTags.join(',')}`);
      const data = await response.json();
      if (data.status === 200) {
        topTagsDiv.innerHTML = data.data
          .map((tag) => `<span class="tag unselected">${tag.keyword}</span>`)
          .join('');
      } else {
        console.error('Erreur lors du chargement des tags associés :', data.message);
      }
    } catch (err) {
      console.error('Erreur lors de la connexion au serveur pour top-tags :', err);
    }
  };

  // Mettre à jour les résultats basés sur les tags sélectionnés
  const updateResults = async () => {
    if (selectedTags.length === 0) {
      resultsDiv.innerHTML = '<p>Aucun tag sélectionné.</p>';
      return;
    }

    try {
      const response = await fetch(`/api/search-data?tags=${selectedTags.join(',')}`);
      const data = await response.json();
      if (data.status === 200) {
        resultsDiv.innerHTML = data.data
          .map(
            (item) => `
            <div class="result-item">
              <h3>${item.name}</h3>
              <p><strong>Data:</strong> ${item.data || 'Aucun contenu'}</p>
              <p><strong>Tags:</strong> ${item.tags}</p>
            </div>`
          )
          .join('');
      } else {
        resultsDiv.innerHTML = `<p>Erreur : ${data.message}</p>`;
        console.error('Erreur lors de la recherche des données:', data.message);
      }
    } catch (err) {
      console.error('Erreur lors de la connexion au serveur pour les résultats :', err);
    }
  };

  // Activer la saisie semi-automatique
  setupAutoComplete(searchInput, suggestionsDiv, '/api/keywords', (tagElement) => {
    const tag = tagElement.textContent.trim();
    addTagToSearchTags(tag); // Ajouter le tag dans search-tags
    searchInput.value = ''; // Vider le champ après sélection
    suggestionsDiv.innerHTML = ''; // Vider les suggestions
  });

  setupAutoComplete(modalInput, modalSuggestionsDiv, '/api/keywords', toggleModalTag);

  // Charger les tags populaires au démarrage
  const loadTopTags = async () => {
    try {
      const response = await fetch('/api/top-tags');
      const data = await response.json();
      if (data.status === 200) {
        topTagsDiv.innerHTML = data.data
          .map((tag) => `<span class="tag unselected">${tag.keyword}</span>`)
          .join('');
      } else {
        console.error('Erreur lors du chargement des tags populaires :', data.message);
      }
    } catch (err) {
      console.error('Erreur lors de la connexion au serveur pour top-tags :', err);
    }
  };

  loadTopTags();
});
