// Mettre à jour les statistiques d'ouverture d'une donnée
router.post('/update-stats', async (req, res) => {
  const { dataId } = req.body;

  if (!dataId) {
    return res.json(formatResponse(400, null, 'L\'ID de la donnée est obligatoire.'));
  }

  const updateQuery = `
    INSERT INTO dataStats (dataId, openCount)
    VALUES (?, 1)
    ON CONFLICT(dataId) DO UPDATE SET openCount = openCount + 1`;

  db.run(updateQuery, [dataId], (err) => {
    if (err) {
      res.json(formatResponse(500, null, 'Erreur lors de la mise à jour des statistiques.'));
    } else {
      res.json(formatResponse(200, null, 'Statistiques mises à jour avec succès.'));
    }
  });
});
