const express = require('express');
const db = require('../../config/database');
const { formatResponse } = require('../../utils/helpers');

const router = express.Router();

// Route pour récupérer les données par défaut
router.get('/default-data', async (req, res) => {
  try {
    // Limites par défaut pour les données récentes et les plus ouvertes
    const defaultRecentLimit = 3;
    const defaultOpenedLimit = 10;

    // Récupérer les limites depuis la table settings
    db.get(
      `SELECT value FROM settings WHERE key = 'most_recent_limit'`,
      (err, rowRecent) => {
        const recentLimit = rowRecent ? parseInt(rowRecent.value, 10) : defaultRecentLimit;

        db.get(
          `SELECT value FROM settings WHERE key = 'most_opened_limit'`,
          (err, rowOpened) => {
            const openedLimit = rowOpened ? parseInt(rowOpened.value, 10) : defaultOpenedLimit;

            // Requêtes pour récupérer les données
            const queries = {
              recent: `
                SELECT id, name, data, dateAdd
                FROM datas
                ORDER BY dateAdd DESC
                LIMIT ?
              `,
              mostOpened: `
                SELECT d.id, d.name, d.data, s.openCount
                FROM datas d
                LEFT JOIN dataStats s ON d.id = s.dataId
                ORDER BY s.openCount DESC
                LIMIT ?
              `,
            };

            const result = { recent: [], mostOpened: [] };

            // Exécuter la requête pour les données récentes
            db.all(queries.recent, [recentLimit], (err, rowsRecent) => {
              if (err) {
                return res.json(formatResponse(500, null, 'Erreur lors de la récupération des données récentes.'));
              }

              result.recent = rowsRecent || [];

              // Exécuter la requête pour les données les plus ouvertes
              db.all(queries.mostOpened, [openedLimit], (err, rowsOpened) => {
                if (err) {
                  return res.json(formatResponse(500, null, 'Erreur lors de la récupération des données les plus ouvertes.'));
                }

                result.mostOpened = rowsOpened || [];
                res.json(formatResponse(200, result));
              });
            });
          }
        );
      }
    );
  } catch (err) {
    res.json(formatResponse(500, null, 'Erreur inattendue lors du chargement des données par défaut.'));
  }
});

module.exports = router;
```

