Voici une version mise à jour et robuste pour gérer les erreurs lors de la récupération des données les plus ouvertes :

```javascript
router.get('/default-data', async (req, res) => {
  try {
    const settingsQuery = `SELECT key, value FROM settings WHERE key IN ('most_recent_limit', 'most_opened_limit')`;
    db.all(settingsQuery, [], (err, settings) => {
      if (err) {
        return res.json(formatResponse(500, null, 'Erreur lors de la récupération des paramètres.'));
      }

      const settingsMap = Object.fromEntries(settings.map((s) => [s.key, parseInt(s.value, 10)]));
      const mostRecentLimit = settingsMap.most_recent_limit || 3;
      const mostOpenedLimit = settingsMap.most_opened_limit || 10;

      const recentQuery = `SELECT * FROM datas ORDER BY dateAdd DESC LIMIT ?`;
      const openedQuery = `
        SELECT d.*, IFNULL(s.openCount, 0) AS openCount
        FROM datas d
        LEFT JOIN dataStats s ON d.id = s.dataId
        ORDER BY openCount DESC LIMIT ?`;

      // Récupérer les données les plus récentes
      db.all(recentQuery, [mostRecentLimit], (err, recentDatas) => {
        if (err) {
          return res.json(formatResponse(500, null, 'Erreur lors de la récupération des données récentes.'));
        }

        // Récupérer les données les plus ouvertes
        db.all(openedQuery, [mostOpenedLimit], (err, openedDatas) => {
          if (err) {
            return res.json(formatResponse(500, null, 'Erreur lors de la récupération des données les plus ouvertes.'));
          }

          res.json(
            formatResponse(200, {
              recent: recentDatas,
              mostOpened: openedDatas,
            })
          );
        });
      });
    });
  } catch (err) {
    res.json(formatResponse(500, null, 'Erreur inattendue.'));
  }
});
```

