### **Code : Mise à jour dans `app.js`**

Voici une version mise à jour de la gestion des tags sélectionnés, des suggestions et des résultats.

```javascript
// Liste des tags sélectionnés
const selectedTags = [];

// Met à jour l'affichage des tags sélectionnés
const updateSelectedTagsDisplay = () => {
  const searchTagsDiv = document.getElementById('search-tags');
  searchTagsDiv.innerHTML = selectedTags
    .map(
      (tag) =>
        `<span class="tag selected">
          ${tag} 
          <span class="remove-tag" data-tag="${tag}">&times;</span>
        </span>`
    )
    .join('');
};

// Gère la suppression d'un tag
document.getElementById('search-tags').addEventListener('click', (e) => {
  if (e.target && e.target.classList.contains('remove-tag')) {
    const tag = e.target.getAttribute('data-tag');
    removeTag(tag);
  }
});

// Supprime un tag des tags sélectionnés
const removeTag = (tag) => {
  const index = selectedTags.indexOf(tag);
  if (index > -1) {
    selectedTags.splice(index, 1);
    updateSelectedTagsDisplay();
    updateTopTags(); // Actualiser les suggestions
    searchData(); // Rechercher les résultats en fonction des tags restants
  }
};

// Ajoute un tag aux tags sélectionnés
const addTagToSelection = (tag) => {
  if (!selectedTags.includes(tag)) {
    selectedTags.push(tag);
    updateSelectedTagsDisplay();
    updateTopTags(); // Actualiser les suggestions
    searchData(); // Rechercher les résultats en fonction des nouveaux tags
  }
};

// Met à jour la liste des suggestions de tags
const updateTopTags = async () => {
  const response = await fetch(`/api/top-tags?tags=${selectedTags.join(',')}`);
  const data = await response.json();

  const topTagsDiv = document.getElementById('top-tags');
  if (data.status === 200) {
    topTagsDiv.innerHTML = data.data
      .map(
        (tag) =>
          `<span class="tag tag-suggestion" data-tag="${tag.keyword}">${tag.keyword}</span>`
      )
      .join('');
  } else {
    console.error('Erreur lors de la mise à jour des tags populaires:', data.message);
  }
};

// Gère les clics sur les suggestions pour les ajouter aux tags sélectionnés
document.getElementById('top-tags').addEventListener('click', (e) => {
  if (e.target && e.target.classList.contains('tag-suggestion')) {
    const tag = e.target.getAttribute('data-tag');
    addTagToSelection(tag);
  }
});

// Recherche les données correspondant aux tags sélectionnés
const searchData = async () => {
  const resultsDiv = document.getElementById('results');
  if (selectedTags.length === 0) {
    resultsDiv.innerHTML = '<p>Aucun tag sélectionné.</p>';
    return;
  }

  const response = await fetch(`/api/search-data?tags=${selectedTags.join(',')}`);
  const data = await response.json();

  if (data.status === 200) {
    if (data.data.length === 0) {
      resultsDiv.innerHTML = '<p>Aucun résultat trouvé.</p>';
    } else {
      resultsDiv.innerHTML = data.data
        .map(
          (item) =>
            `<div class="result-item">
              <h3>${item.name}</h3>
              <p><strong>Data:</strong> ${item.data || 'Aucun contenu'}</p>
              <p><strong>Tags:</strong> ${item.tags}</p>
            </div>`
        )
        .join('');
    }
  } else {
    resultsDiv.innerHTML = `<p>Erreur : ${data.message}</p>`;
    console.error('Erreur lors de la recherche des données:', data.message);
  }
};
```

