          SELECT dk.dataId
          FROM dataKeyword dk
          JOIN keywords k ON dk.keywordId = k.id
          WHERE k.keyword IN (${tags.map(() => '?').join(',')})
        )
      `;
      params = tags;
    }

    query += `
      GROUP BY k.id
      ORDER BY usage_count DESC
      LIMIT ?
    `;
    params.push(limit);

    db.all(query, params, (err, rows) => {
      if (err) {
        console.error('Erreur SQL pour getTopTags:', err.message);
        return reject('Erreur lors de la récupération des tags populaires.');
      }
      resolve(rows);
    });
  });
};

module.exports = { getTopTags };
```

#### 2. **Vérifier les données dans la base**

- Assurez-vous que la table `dataKeyword` contient bien des relations entre `dataId` et `keywordId`.
- Assurez-vous que les mots-clés dans la table `keywords` correspondent bien aux IDs dans `dataKeyword`.

