      'UPDATE settings SET value = ? WHERE key = ?',
      [value, key],
      function (err) {
        if (err) {
          console.error('Erreur SQL lors de la mise à jour du paramètre :', err.message);
          reject(err);
        } else {
          console.log(`Paramètre mis à jour : ${key} = ${value}`);
          resolve(this.changes > 0); // `this.changes` indique le nombre de lignes affectées
        }
      }
    );
  });
};

/**
 * Récupère tous les paramètres de la table settings.
 * @returns {Promise<Array>} - Renvoie une liste de tous les paramètres.
 */
const getSettings = () => {
  return new Promise((resolve, reject) => {
    db.all('SELECT key, value FROM settings', [], (err, rows) => {
      if (err) {
        console.error('Erreur SQL lors de la récupération des paramètres :', err.message);
        reject(err);
      } else {
        resolve(rows);
      }
    });
  });
};

module.exports = { updateSettingValue, getSettings };
