const updateSettingValue = (key, value) => {
  return new Promise((resolve, reject) => {
    db.run(
      'UPDATE settings SET value = ? WHERE key = ?',
      [value, key],
      function (err) {
        if (err) {
          reject(err);
        } else {
          resolve(this.changes > 0); // Renvoie true si au moins une ligne a été mise à jour
        }
      }
    );
  });
};
