    if (!data || (!data.recent && !data.mostOpened)) {
      return res.json(formatResponse(404, null, 'Aucune donnée disponible.'));
    }
    res.json(formatResponse(200, data));
  } catch (err) {
    console.error('Erreur lors de la récupération des données par défaut :', err.message);
    res.json(formatResponse(500, null, 'Erreur lors de la récupération des données par défaut.'));
  }
});

module.exports = router;
