const db = require('../config/database');

/**
 * Recherche des données basées sur les tags.
 * @param {string[]} tags - Liste des tags à rechercher.
 * @returns {Promise<Array>} - Liste des données correspondantes ou un message si aucun résultat n'est trouvé.
 */
const searchDataByTags = (tags) => {
  return new Promise((resolve, reject) => {
    if (!tags.length) return resolve({ message: 'Veuillez spécifier au moins un tag.', data: [] });

    const placeholders = tags.map(() => '?').join(',');
    const sql = `
      SELECT d.id, d.name, d.data, GROUP_CONCAT(k.keyword) AS tags
      FROM datas d
      LEFT JOIN dataKeyword dk ON d.id = dk.dataId
      LEFT JOIN keywords k ON dk.keywordId = k.id
      WHERE k.keyword IN (${placeholders})
      GROUP BY d.id
      ORDER BY d.dateAdd DESC
    `;

    console.log('Requête SQL pour rechercher les données :', sql); // Debug
    console.log('Tags reçus pour la recherche :', tags); // Debug

    db.all(sql, tags, (err, rows) => {
      if (err) {
        console.error('Erreur SQL pour searchDataByTags :', err.message); // Debug
        reject(new Error('Erreur lors de la recherche.'));
      } else if (!rows || rows.length === 0) {
        console.log('Aucun résultat trouvé pour les tags :', tags); // Debug
        resolve({ message: 'Aucun résultat trouvé.', data: [] });
      } else {
        console.log('Données récupérées :', rows); // Debug
        resolve({ message: '', data: rows });
      }
    });
  });
};

module.exports = { searchDataByTags };
```

