    if (data.status === 200) {
      document.getElementById('modal-top-tags').innerHTML = data.data
        .map((tag) => `<span class="tag tag-suggestion" data-tag="${tag.keyword}">${tag.keyword}</span>`)
        .join('');
    } else {
      console.error('Erreur lors du chargement des top tags :', data.message);
    }
  } catch (err) {
    console.error('Erreur lors de la connexion au serveur pour les top tags :', err);
  }
