// Gestion de la saisie semi-automatique dans la modal
const setupModalAutoComplete = () => {
  modalInput.addEventListener('input', async () => {
    const query = modalInput.value.trim();
    if (!query) {
      modalSuggestions.innerHTML = '';
      return;
    }

    try {
      const response = await fetch(`/api/keywords?search=${query}`);
      const data = await response.json();
      if (data.status === 200) {
        modalSuggestions.innerHTML = data.data
          .map((tag) => `<span class="tag tag-suggestion" data-tag="${tag.keyword}">${tag.keyword}</span>`)
          .join('');
      } else {
        console.error('Erreur lors de la récupération des suggestions :', data.message);
      }
    } catch (err) {
      console.error('Erreur lors de la connexion au serveur pour les suggestions :', err);
    }
  });

  modalSuggestions.addEventListener('click', (e) => {
    if (e.target && e.target.classList.contains('tag-suggestion')) {
      const tag = e.target.getAttribute('data-tag');
      if (!modalSelectedTags.includes(tag)) {
        modalSelectedTags.push(tag);
        updateModalSelectedTags();
      }
    }
  });
};

