const updateModalSelectedTags = () => {
  modalSelectedTagsDiv.innerHTML = modalSelectedTags
    .map(
      (tag) =>
        `<span class="tag selected-tag">${tag} <span class="remove-tag" data-tag="${tag}">&times;</span></span>`
    )
    .join('');

  // Gestion de la suppression des tags
  document.querySelectorAll('.remove-tag').forEach((btn) =>
    btn.addEventListener('click', (e) => {
      const tag = e.target.getAttribute('data-tag');
      const index = modalSelectedTags.indexOf(tag);
