    try {
      const response = await fetch('/api/settings');
      const data = await response.json();
      if (data.status === 200) {
        settingsContainer.innerHTML = data.data
          .map(
            (setting) => `
              <div class="setting-item">
                <label for="${setting.key}">${setting.name}</label>
                <input
                  type="text"
                  id="${setting.key}"
                  value="${setting.value}"
                  onchange="window.updateSetting('${setting.key}', this.value)"
                />
              </div>
            `
          )
          .join('');
      } else {
        settingsContainer.innerHTML = `<p>Erreur : ${data.message}</p>`;
      }
    } catch (err) {
      console.error('Erreur lors de la récupération des paramètres :', err);
      settingsContainer.innerHTML = '<p>Erreur lors de la récupération des paramètres.</p>';
    }
  };

  // Charger les pages existantes
  const loadPages = async () => {
    try {
      const response = await fetch('/api/pages');
      const data = await response.json();
      if (data.status === 200) {
        pagesListContainer.innerHTML = data.data
          .map(
            (page) => `
              <div class="page-item">
                <h3>${page.pageName}</h3>
                <p>Tag: ${page.tagName} | Icône: <i class="${page.icon}"></i></p>
                <button onclick="window.loadPage(${page.id})">Voir les détails</button>
              </div>
            `
          )
          .join('');
      } else {
        pagesListContainer.innerHTML = `<p>Erreur : ${data.message}</p>`;
      }
    } catch (err) {
      console.error('Erreur lors de la récupération des pages :', err);
      pagesListContainer.innerHTML = '<p>Erreur lors de la récupération des pages.</p>';
    }
  };

  // Charger les détails d'une page (fonction globale pour onclick)
  window.loadPage = async (pageId) => {
    try {
      const response = await fetch(`/api/pages/${pageId}`);
      const data = await response.json();
      if (data.status === 200) {
        alert(`Détails de la page : ${JSON.stringify(data.data, null, 2)}`);
      } else {
        alert(`Erreur : ${data.message}`);
      }
    } catch (err) {
      console.error('Erreur lors du chargement de la page :', err);
      alert('Erreur lors du chargement de la page.');
    }
  };

  // Valider une page
  const validatePage = (pageName, icon, selectedTag) => {
    if (!pageName || !icon || !selectedTag) {
      alert('Veuillez remplir tous les champs.');
      return false;
    }
    if (pageName.length < 3) {
      alert('Le nom de la page doit comporter au moins 3 caractères.');
      return false;
    }
    if (!icon.startsWith('fa-')) {
      alert('Le champ Icône doit être un nom valide de classe Font Awesome.');
      return false;
    }
    return true;
  };

  // Ajouter une nouvelle page
  const addPage = async () => {
    const pageName = document.getElementById('page-name-input').value.trim();
    const icon = document.getElementById('page-icon-input').value.trim();
    const selectedTag = selectedPageTags[0]; // On utilise le premier tag sélectionné

    if (!validatePage(pageName, icon, selectedTag)) {
      return;
    }

    try {
      const response = await fetch('/api/pages', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          tagId: selectedTag.id,
          pageName: pageName,
          pageIdent: pageName.toLowerCase().replace(/\s+/g, '-'),
          icon: icon,
        }),
      });
      const data = await response.json();
      if (data.status === 201) {
        alert('Page ajoutée avec succès.');
        loadPages();
        document.getElementById('page-name-input').value = '';
        document.getElementById('page-icon-input').value = '';
        selectedPageTags = [];
        tagInputElement.value = '';
      } else {
        alert(`Erreur : ${data.message}`);
      }
    } catch (err) {
      console.error('Erreur lors de l\'ajout de la page :', err);
      alert('Erreur lors de l\'ajout de la page.');
    }
  };

  // Configuration de l'auto-complétion pour les tags
  const setupPageAutoComplete = () => {
    setupAutoComplete(tagInputElement, '/api/keywords', (selectedTag) => {
      selectedPageTags = [selectedTag];
      console.log('Tag sélectionné pour la page :', selectedTag);
    });
  };

  // Écouteur pour le bouton Ajouter une page
  if (addPageButton) {
    addPageButton.addEventListener('click', addPage);
  } else {
    console.error("Erreur : Le bouton d'ajout de page est introuvable.");
  }

  // Définir la fonction `updateSetting` dans le contexte global
  window.updateSetting = async (key, newValue) => {
    if (!confirm(`Enregistrer la nouvelle valeur : ${newValue} ?`)) return;

    try {
      const response = await fetch(`/api/settings/${key}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ value: newValue }),
      });
      const data = await response.json();
      if (data.status === 200) {
        alert('Paramètre mis à jour avec succès.');
      } else {
        alert(`Erreur : ${data.message}`);
      }
    } catch (err) {
      console.error('Erreur lors de la mise à jour du paramètre :', err);
      alert('Erreur lors de la mise à jour.');
    }
  };

  // Charger les paramètres et les pages au démarrage
  loadSettings();
  loadPages();

  // Initialisation de l'auto-complétion
  setupPageAutoComplete();
});
